+    assert!(
+        script.contains("debug-metadata.json"),
+        "script must emit debug metadata artifact"
+    );
+    assert!(
+        script.contains("asupersync.js.map") && script.contains("asupersync_bg.wasm.map"),
+        "script must handle JS and WASM source maps"
+    );
+}
